import anthropic

client = anthropic.Anthropic()

# STEP 1: Read and encode PDF
with open("research_paper.pdf", "rb") as f:
    pdf_bytes = f.read()
    encoded_pdf = pdf_bytes  # For base64, use base64.b64encode(pdf_bytes).decode()

# STEP 2: Create message with Citations enabled
response = client.messages.create(
    model="claude-3-5-sonnet-20241022",
    max_tokens=1024,
    messages=[{
        "role": "user",
        "content": [
            {
                "type": "document",
                "source": {
                    "type": "base64",
                    "media_type": "application/pdf",
                    "data": encoded_pdf
                },
                "title": "research_paper.pdf",
                "citations": {  # ← Enable Citations
                    "enabled": True
                }
            },
            {
                "type": "text",
                "text": "What were the key findings and methodology?"
            }
        ]
    }]
)

# STEP 3: Print response with citations
print(response.content[0].text)
# Output: "The methodology used a randomized controlled trial design [p. 45].
#          Key findings showed 25% improvement in outcomes [pp. 78-82]."

# STEP 4: Access structured citation metadata
for citation in response.citations:
    print(f"\nCited text: {citation.cited_text}")
    print(f"Source: {citation.document_title} [p. {citation.start_page_number}]")
